/* Color palette: red (#ff0000), black (#000), white (#fff) */
:root {
  --red: #ff0000;
  --black: #000;
  --white: #fff;
}

* { box-sizing: border-box; }
html, body { height: 100%; }

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Arial, sans-serif;
  color: var(--black);
  background: var(--white);
  line-height: 1.6;
  font-size: 16px;
}

img { max-width: 100%; height: auto; display: block; }

.container { width: min(960px, 92%); margin: 0 auto; }

/* Typography */
h1 { font-size: clamp(1.75rem, 4.5vw, 2.5rem); line-height: 1.2; margin: 0 0 0.5rem; }
h2 { font-size: clamp(1.375rem, 3.2vw, 2rem); line-height: 1.25; margin: 0 0 1rem; }
h3 { font-size: clamp(1.125rem, 2.6vw, 1.375rem); margin: 0 0 0.5rem; }
p { margin: 0 0 1rem; }

/* Links & buttons */
a { color: var(--red); text-decoration: none; }
a:hover, a:focus { text-decoration: underline; }

.btn, .cta {
  display: inline-block;
  background: var(--red);
  color: var(--white);
  border: 2px solid var(--red);
  padding: 0.75rem 1.25rem;
  border-radius: 0;
  font-weight: 600;
  text-align: center;
}
.btn:hover, .btn:focus, .cta:hover, .cta:focus {
  background: var(--black);
  border-color: var(--black);
  color: var(--white);
}

/* Accessibility focus */
:focus { outline: 2px solid var(--red); outline-offset: 2px; }

/* Hero */
.hero {
  background: var(--black);
  color: var(--white);
  padding: 3.5rem 0 3rem;
  text-align: center;
  border-bottom: 4px solid var(--red);
}
.hero .subtitle { color: var(--white); opacity: 1; margin: 0 0 1.25rem; }
.hero .cta { margin-top: 0.5rem; }

/* Sections */
.section { padding: 2.5rem 0; }
.section + .section { border-top: 4px solid var(--red); }
.section-intro { max-width: 60ch; }

/* Services */
.services-list {
  list-style: none;
  margin: 1.25rem 0 0;
  padding: 0;
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}
.service-item {
  border: 2px solid var(--black);
  padding: 1rem;
  background: var(--white);
}
.service-title { margin-bottom: 0.25rem; }
.service-text { margin: 0; }

/* Contact */
.contact-form { margin-top: 1rem; max-width: 720px; }
.form-row { display: grid; gap: 0.5rem; margin-bottom: 1rem; }
label { font-weight: 600; }
input, textarea {
  width: 100%;
  padding: 0.75rem;
  border: 2px solid var(--black);
  background: var(--white);
  color: var(--black);
}
input:focus, textarea:focus {
  border-color: var(--red);
  outline: 2px solid var(--red);
  outline-offset: 0;
}

/* Footer */
.footer { border-top: 4px solid var(--red); padding: 1.25rem 0; text-align: center; }
.footer p { margin: 0; }

/* Responsive enhancements */
@media (min-width: 600px) {
  .section { padding: 3rem 0; }
  .services-list { gap: 1.25rem; }
}

@media (min-width: 900px) {
  .services-list { grid-template-columns: repeat(2, 1fr); }
}

document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('contact-form');
  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const nameEl = document.getElementById('name');
      const nameVal = nameEl && 'value' in nameEl ? nameEl.value.trim() : '';
      alert(`Thank you${nameVal ? ', ' + nameVal : ''}! Your message has been received.`);
      form.reset();
    });
  }
});

{
  "name": "lab-technician-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal single-page landing site for a lab technician.",
  "scripts": {
    "test": "jest"
  },
  "devDependencies": {
    "jest": "^29.7.0"
  }
}

const fs = require('fs');
const path = require('path');

describe('Landing page', () => {
  test('index.html contains the hero title', () => {
    const html = fs.readFileSync(path.join(__dirname, '..', 'index.html'), 'utf8');
    expect(html).toMatch(/<h1[^>]*id=["']hero-title["'][^>]*>\s*Professional Lab Technician\s*<\/h1>/i);
  });
});
